107	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
108	  let quotesSeen = 0;
109	  const results = scenario.steps.map((step) => {
110	    const isFollowUp = quotesSeen > 0;
111	    quotesSeen += 1;
112	    return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
113	  });
114	  return { results };
115	};
