const isQuote = (step: QuoteStep): boolean => step.op === "quote";

const priorQuoteCount = (steps: QuoteStep[], index: number): number =>
  steps.slice(0, index).filter(isQuote).length;

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map((step, index) => {
    const isFollowUp = priorQuoteCount(scenario.steps, index) > 0;
    return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
  });
  return { results };
};
